// src/app/chat/components/ChatSidebar.tsx
import { Plus, ChevronDown, Trash2, Loader2, MoreHorizontal, Pencil, LogOut, X, PanelLeftClose, PanelLeftOpen, MessageSquare } from "lucide-react";
import type { Mode } from "@/app/api/chat";
import { useState, useEffect } from "react";
import { useChatHistory, useDeleteSession, useUpdateSessionTitle } from "@/app/api/chat";
import { useToast } from "@/shared/hooks/useToast";
import { useGetProfile } from "@/app/api/auth";
import { storageService } from "@/app/services/storageService";
import { useQueryClient } from "@tanstack/react-query";

type Props = {
  open: boolean;
  collapsed: boolean;
  onToggleCollapse: () => void;
  mode: Mode;
  onModeChange: (mode: Mode) => void;
  onNewChat: () => void;
  onClose: () => void;
  onLoadChat: (sessionId: string) => void;
  currentSessionId?: string;
  onDeleteSession: (sessionId: string) => void;
  isPremium: boolean;
  remainingQuota: number;
  onUpgrade: () => void;
};
const topicIcons: Record<string, string> = {
  marketing: "data:image/png;base64,",
  branding: "data:image/png;base64,",
  pricing: "data:image/png;base64,",
  positioning: "data:image/png;base64,",
  digital_marketing: "data:image/png;base64,",
  content_plan: "data:image/png;base64,",
  sales_system: "data:image/png;base64,",
  market_analyst: "data:image/png;base64,",
  product_development: "data:image/png;base64,",
};
export default function ChatSidebar({
  open,
  collapsed,
  onToggleCollapse,
  mode,
  onModeChange,
  onNewChat,
  onClose,
  onLoadChat,
  onDeleteSession,
  currentSessionId,
  isPremium,
  remainingQuota,
  onUpgrade,

}: Props) {
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [modeDropdownOpen, setModeDropdownOpen] = useState(false);
  const [savingTitle, setSavingTitle] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalSessionId, setModalSessionId] = useState("");
  const [modalTitle, setModalTitle] = useState("");
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);


  const toast = useToast();
  const updateTitleMutation = useUpdateSessionTitle();
  const { data: historyData, isLoading } = useChatHistory({ limit: 20 });
  const deleteSessionMutation = useDeleteSession();
  const { data: profileData } = useGetProfile();
  const queryClient = useQueryClient();

  const handleLogout = () => {
    storageService.remove('token');
    queryClient.clear();
    window.location.href = '/auth/login?direct=1';
  };

  const modes = [
    { id: "diagnostic" as Mode, name: "Probe", desc: "Temukan masalah bisnis" },
    { id: "engine" as Mode, name: "Thrive", desc: "Panduan terstruktur" },
  ];

  useEffect(() => {
    const handleClickOutside = () => setActiveMenuId(null);
    if (activeMenuId) {
      document.addEventListener("click", handleClickOutside);
    }
    return () => document.removeEventListener("click", handleClickOutside);
  }, [activeMenuId]);

  const handleLoadChat = (sessionId: string) => {
    onLoadChat(sessionId);
    onClose();
  };

  const handleDeleteChat = async (e: React.MouseEvent, sessionId: string) => {
    e.stopPropagation();
    setActiveMenuId(null);
    setDeleteConfirmId(sessionId); // buka modal konfirmasi
  };

  const handleConfirmDelete = async () => {
    if (!deleteConfirmId) return;
    try {
      await deleteSessionMutation.mutateAsync(deleteConfirmId);
      onDeleteSession(deleteConfirmId);
    } catch {
      toast.error("Gagal menghapus chat");
    } finally {
      setDeleteConfirmId(null);
    }
  };
  const handleStartEdit = (e: React.MouseEvent, session: any) => {
    e.stopPropagation();
    setActiveMenuId(null);
    setModalSessionId(session.session_id);
    setModalTitle(getSessionTitle(session));
    setModalOpen(true);
  };

  const handleSaveTitle = async () => {
    if (!modalTitle.trim()) { setModalOpen(false); return; }
    setSavingTitle(true);
    try {
      await updateTitleMutation.mutateAsync({ sessionId: modalSessionId, title: modalTitle.trim() });
      toast.success("Judul berhasil diubah");
      setModalOpen(false);
    } catch {
      toast.error("Gagal mengubah judul");
    } finally {
      setSavingTitle(false);
    }
  };

  const getSessionTitle = (session: any) => {
    if (session.title) return session.title;
    if (session.mode === "engine" && session.topic) {
      const topicLabels: Record<string, string> = {
        pricing: "Pricing Strategy", branding: "Branding Strategy",
        marketing: "Marketing Strategy", positioning: "Market Positioning",
        digital_marketing: "Digital Marketing", content_plan: "Content Planning",
        sales_system: "Sales System", market_analyst: "Market Analysis",
        product_development: "Product Development",
      };
      return topicLabels[session.topic] || "Engine Session";
    }
    return "New Chat";
  };

  const getModeBadge = (sessionMode: Mode, topic?: string) => {
    if (sessionMode === "engine" && topic && topicIcons[topic]) {
      return <img src={topicIcons[topic]} alt={topic} className="w-6 h-6 object-contain" />;
    }
    const modeIcons: Record<Mode, string> = {
      diagnostic: "🔍", discuss: "💬", engine: "⚙️", explorer: "🚀",
    };
    return <span className="text-base">{modeIcons[sessionMode] || "💬"}</span>;
  };

  const currentModeName = modes.find((m) => m.id === mode)?.name ?? "Probe";
  const userName = profileData?.data?.data?.name || 'User';
  const userInitial = userName.charAt(0).toUpperCase();

  return (
    <>
      {/* Backdrop mobile */}
      {open && (
        <div
          className="fixed inset-0 bg-black/30 z-40 backdrop-blur-sm md:hidden"
          onClick={onClose}
        />
      )}

      <aside className={`
        fixed md:sticky top-0 left-0 z-50
        h-screen bg-white border-r border-gray-200
        flex flex-col shadow-xl md:shadow-none
        transition-all duration-300 ease-in-out
        ${open ? "translate-x-0" : "-translate-x-full md:translate-x-0"}
        ${collapsed ? "md:w-[60px]" : "w-[280px]"}
      `}>

        {/* ── COLLAPSED STATE (desktop icon-only bar) ── */}
        {collapsed && (
          <div className="hidden md:flex flex-col items-center h-full py-4 gap-2">
            {/* Expand button */}
            <button
              onClick={onToggleCollapse}
              className="p-2 rounded-lg hover:bg-gray-100 transition-colors text-gray-500"
              title="Buka sidebar"
            >
              <PanelLeftOpen className="w-5 h-5" />
            </button>

            {/* New chat */}
            <button
              onClick={onNewChat}
              className="p-2 rounded-lg bg-red-600 hover:bg-red-700 transition-colors text-white"
              title="New chat"
            >
              <Plus className="w-5 h-5" />
            </button>

            {/* Divider */}
            <div className="w-8 h-px bg-gray-200 my-1" />

            {/* Chat history icons */}
            {/* Chat history icons */}
            <div className="flex-1 overflow-y-auto w-full flex flex-col items-center gap-1 px-1">
              {historyData?.sessions
                ?.filter((session) => {
                  if (mode === "diagnostic" || mode === "discuss") {
                    return session.mode === "diagnostic" || session.mode === "discuss";
                  }
                  return session.mode === mode;
                })
                .map((session) => (
                  <button
                    key={session.session_id}
                    onClick={() => handleLoadChat(session.session_id)}
                    title={getSessionTitle(session)}
                    className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all ${currentSessionId === session.session_id
                      ? "bg-red-50 border border-red-200"
                      : "hover:bg-gray-100"
                      }`}
                  >
                    {getModeBadge(session.mode as Mode, session.topic)}
                  </button>
                ))}
            </div>
            {/* User avatar */}
            <button
              onClick={() => setShowLogoutConfirm(true)}
              className="w-10 h-10 bg-gradient-to-br from-red-600 to-red-700 rounded-full flex items-center justify-center text-white font-bold text-sm shadow-md hover:opacity-90 transition-opacity"
              title={`${userName} — Logout`}
            >
              {userInitial}
            </button>
          </div>
        )}

        {/* ── EXPANDED STATE ── */}
        {!collapsed && (
          <>
            {/* Header */}
            <div className="p-4 pb-3 w-full flex items-center justify-between flex-shrink-0">
              <img src="/ready.png" alt="REDGO AI Logo" className="h-9 w-auto object-contain max-w-full" />
              {/* Close — mobile */}
              <button
                onClick={onClose}
                className="md:hidden p-1.5 rounded-lg hover:bg-gray-100 transition-colors text-gray-500"
              >
                <X className="w-5 h-5" />
              </button>
              {/* Collapse — desktop */}
              <button
                onClick={onToggleCollapse}
                className="hidden md:flex p-1.5 rounded-lg hover:bg-gray-100 transition-colors text-gray-500"
                title="Tutup sidebar"
              >
                <PanelLeftClose className="w-5 h-5" />
              </button>
            </div>

            {/* New Chat Button */}
            <div className="px-4 pb-2 flex-shrink-0">
              <button
                onClick={() => { onNewChat(); onClose(); }}
                className="w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-gradient-to-r from-red-600 to-red-700 text-white rounded-xl hover:from-red-700 hover:to-red-800 transition-all shadow-md font-semibold text-sm"
              >
                <Plus className="w-4 h-4" />
                <span>New chat</span>
              </button>
            </div>

            {/* Mode Select */}
            <div className="px-4 pb-3 flex-shrink-0">
              <div className="relative w-1/2">
                <button
                  onClick={() => setModeDropdownOpen(!modeDropdownOpen)}
                  className="w-full flex items-center justify-between pl-3 pr-2 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-200   rounded-xl hover:bg-red-50 hover:border-red-300 hover:text-red-700 transition-colors"
                >
                  <span className="text-gray-400 font-normal">Mode</span>
                  <ChevronDown className={`w-3.5 h-3.5 transition-transform ${modeDropdownOpen ? "rotate-180" : ""}`} />
                </button>

                {modeDropdownOpen && (
                  <>
                    <div className="fixed inset-0 z-40" onClick={() => setModeDropdownOpen(false)} />
                    <div className="absolute top-full left-0 mt-1 w-full bg-white border border-gray-200 rounded-xl shadow-lg z-50 overflow-hidden">
                      {modes.map((m) => (
                        <button
                          key={m.id}
                          onClick={() => { onModeChange(m.id); setModeDropdownOpen(false); }}
                          className={`w-full text-left px-3 py-2 text-sm font-medium transition-colors ${mode === m.id
                            ? "bg-red-50 text-red-700"
                            : "text-gray-700 hover:bg-red-50 hover:text-red-700"
                            }`}
                        >
                          {m.name}
                        </button>
                      ))}
                    </div>
                  </>
                )}
              </div>
            </div>

            <div className="mx-3 border-t border-gray-100 mb-2 flex-shrink-0" />

            {/* Recents Label */}
            <div className="px-4 pt-1 pb-1 flex-shrink-0">
              <p className="text-xs font-medium text-gray-400 tracking-wide">Recents</p>
            </div>


            {/* Chat History */}
            <div className="flex-1 overflow-y-auto px-2">
              {isLoading && (
                <div className="flex items-center justify-center py-12">
                  <Loader2 className="w-6 h-6 text-red-600 animate-spin" />
                </div>
              )}

              {!isLoading && (!historyData?.sessions || historyData.sessions.filter(s => {
                if (mode === "diagnostic" || mode === "discuss") {
                  return s.mode === "diagnostic" || s.mode === "discuss";
                }
                return s.mode === mode;
              }).length === 0) && (
                  <div className="text-center py-8 px-4">
                    <p className="text-sm text-gray-400">Belum ada percakapan {currentModeName}</p>
                  </div>
                )}
              {!isLoading && historyData?.sessions && historyData.sessions.length > 0 && (
                <div className="space-y-1 animate-[fadeIn_0.25s_ease]">
                  {historyData.sessions
                    .filter((session) => {
                      if (mode === "diagnostic" || mode === "discuss") {
                        return session.mode === "diagnostic" || session.mode === "discuss";
                      }
                      return session.mode === mode;
                    })
                    .map((session) => (
                      <div key={session.session_id} className="relative group">
                        <button
                          onClick={() => handleLoadChat(session.session_id)}
                          className={`
                          w-full text-left px-3 py-3 rounded-xl
                          transition-all relative flex items-start gap-3
                          ${currentSessionId === session.session_id
                              ? "bg-red-50 border border-red-200"
                              : "hover:bg-gray-50 hover:translate-x-1 transition-all duration-200 border border-transparent"}
                        `}
                        >
                          <div className="flex-shrink-0 w-8 h-8 flex items-center justify-center mt-0.5">
                            {getModeBadge(session.mode as Mode, session.topic)}
                          </div>
                          <div className="flex-1 min-w-0 pr-6">
                            <div className={`text-sm font-medium truncate ${currentSessionId === session.session_id ? "text-red-700" : "text-gray-900"
                              }`}>
                              {getSessionTitle(session)}
                            </div>
                            {session.mode === "engine" && session.topic && (
                              <div className="text-xs text-gray-500 mt-0.5 capitalize">
                                {session.topic.replace("_", " ")} • {session.sub_mode}
                              </div>
                            )}
                          </div>
                        </button>

                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            setActiveMenuId(activeMenuId === session.session_id ? null : session.session_id);
                          }}
                          className="absolute right-2 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 p-1.5 hover:bg-gray-200 rounded-lg transition-all"
                        >
                          <MoreHorizontal className="w-4 h-4 text-gray-500" />
                        </button>

                        {activeMenuId === session.session_id && (
                          <div
                            className="absolute right-2 top-10 z-50 bg-white rounded-xl shadow-xl border border-gray-200 py-1 w-36 overflow-hidden"
                            onClick={(e) => e.stopPropagation()}
                          >
                            <button
                              onClick={(e) => handleStartEdit(e, session)}
                              className="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-black hover:bg-gray-50 hover:translate-x-1 transition-all duration-200 transition-colors"
                            >
                              <Pencil className="w-3.5 h-3.5 text-gray-500" />
                              Edit judul
                            </button>
                            <button
                              onClick={(e) => handleDeleteChat(e, session.session_id)}
                              disabled={deleteSessionMutation.isPending}
                              className="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-red-600 hover:bg-red-50 transition-colors"
                            >
                              {deleteSessionMutation.isPending
                                ? <Loader2 className="w-3.5 h-3.5 animate-spin" />
                                : <Trash2 className="w-3.5 h-3.5" />}
                              Hapus
                            </button>

                          </div>
                        )}
                      </div>
                    ))}
                </div>
              )}
            </div>

            {/* Bottom Section */}
            <div className="border-t border-gray-200 p-3 flex-shrink-0">
              <div className="flex items-center gap-3 px-3 py-2">
                <div className="w-10 h-10 bg-gradient-to-br from-red-600 to-red-700 rounded-full flex items-center justify-center text-white font-bold text-lg flex-shrink-0 shadow-md">
                  {userInitial}
                </div>
                <div className="flex-1 text-left min-w-0">
                  <div className="text-sm font-semibold text-gray-900 truncate">{userName}</div>
                  <div className="flex items-center gap-1.5">
                    <span className="text-xs text-gray-500">{currentModeName}</span>
                    <span className="text-gray-300 text-xs">·</span>
                    <button
                      onClick={isPremium ? undefined : onUpgrade}
                      className={`text-xs font-semibold px-2 py-0.5 rounded-full transition-colors ${isPremium
                          ? "bg-amber-100 text-amber-600 cursor-default"
                          : "bg-gray-100 text-gray-500 hover:bg-amber-100 hover:text-amber-600 cursor-pointer"
                        }`}
                    >
                      {isPremium ? "Premium" : "Free"}
                    </button>
                  </div>
                </div>
                <button
                  onClick={() => setShowLogoutConfirm(true)}
                  className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  title="Logout"
                >
                  <LogOut className="w-4 h-4" />
                </button>
              </div>
            </div>
          </>
        )}
      </aside>

      {/* Modal Edit Judul */}
      {modalOpen && (
        <>
          <div className="fixed inset-0 bg-black/50 z-[100] backdrop-blur-sm" onClick={() => setModalOpen(false)} />
          <div className="fixed inset-0 z-[101] flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6"
              style={{ animation: "modalSlideUp 0.25s cubic-bezier(0.34,1.56,0.64,1)" }}
            >

              <h3 className="text-lg font-semibold text-gray-900 mb-4">Edit Judul Chat</h3>
              <input
                autoFocus
                value={modalTitle}
                onChange={(e) => setModalTitle(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") handleSaveTitle();
                  if (e.key === "Escape") setModalOpen(false);
                }}
                className="w-full px-4 py-3 border border-gray-300 rounded-xl text-sm outline-none focus:border-red-400 focus:ring-2 focus:ring-red-100"
                placeholder="Masukkan judul..."
              />
              <div className="flex gap-2 mt-4">
                <button onClick={() => setModalOpen(false)} className="flex-1 px-4 py-2.5 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50 hover:translate-x-1 transition-all duration-200">
                  Batal
                </button>
                <button
                  onClick={handleSaveTitle}
                  disabled={savingTitle}
                  className="flex-1 px-4 py-2.5 bg-red-600 text-white rounded-xl text-sm font-medium hover:bg-red-700 transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
                >
                  {savingTitle && <Loader2 className="w-4 h-4 animate-spin" />}
                  Simpan
                </button>
              </div>
            </div>
          </div>
        </>
      )}

      {/* Delete Confirmation Modal */}
      {deleteConfirmId && (
        <>
          <div
            className="fixed inset-0 bg-black/50 z-[100] backdrop-blur-sm"
            onClick={() => setDeleteConfirmId(null)}
          />
          <div className="fixed inset-0 z-[101] flex items-center justify-center p-4">
            <div
              className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6"
              style={{ animation: "modalSlideUp 0.25s cubic-bezier(0.34,1.56,0.64,1)" }}
            >
              <div className="flex justify-center mb-4">
                <div className="relative">
                  <div className="w-14 h-14 rounded-2xl bg-red-50 flex items-center justify-center">
                    <Trash2 className="w-6 h-6 text-red-500" strokeWidth={1.75} />
                  </div>
                  <div className="absolute -inset-1 rounded-2xl border border-red-100" />
                </div>
              </div>
              <div className="text-center mb-6">
                <h3 className="text-base font-semibold text-gray-900 mb-1">Hapus chat ini?</h3>
                <p className="text-sm text-gray-400 leading-relaxed">
                  Chat yang dihapus tidak bisa<br />dikembalikan lagi.
                </p>
              </div>
              <div className="flex gap-2">
                <button
                  onClick={() => setDeleteConfirmId(null)}
                  className="flex-1 py-2.5 rounded-xl text-sm font-medium text-gray-600 bg-gray-100 hover:bg-gray-200 transition-all active:scale-95"
                >
                  Batal
                </button>
                <button
                  onClick={handleConfirmDelete}
                  disabled={deleteSessionMutation.isPending}
                  className="flex-1 py-2.5 rounded-xl text-sm font-medium text-white bg-red-500 hover:bg-red-600 transition-all active:scale-95 shadow-sm shadow-red-200 flex items-center justify-center gap-2 disabled:opacity-50"
                >
                  {deleteSessionMutation.isPending && <Loader2 className="w-4 h-4 animate-spin" />}
                  Hapus
                </button>
              </div>
            </div>
          </div>
        </>
      )}

      {/* Logout Confirmation Modal */}
      {showLogoutConfirm && (
        <>
          <div
            className="fixed inset-0 bg-black/50 z-[100] backdrop-blur-sm"
            onClick={() => setShowLogoutConfirm(false)}
          />
          <div className="fixed inset-0 z-[101] flex items-center justify-center p-4">
            <div
              className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6"
              style={{ animation: "modalSlideUp 0.25s cubic-bezier(0.34,1.56,0.64,1)" }}
            >
              <div className="flex justify-center mb-4">
                <div className="relative">
                  <div className="w-14 h-14 rounded-2xl bg-red-50 flex items-center justify-center">
                    <LogOut className="w-6 h-6 text-red-500" strokeWidth={1.75} />
                  </div>
                  <div className="absolute -inset-1 rounded-2xl border border-red-100" />
                </div>
              </div>
              <div className="text-center mb-6">
                <h3 className="text-base font-semibold text-gray-900 mb-1">Keluar dari akun?</h3>
                <p className="text-sm text-gray-400 leading-relaxed">
                  Sesi kamu akan berakhir.<br />Sampai jumpa lagi!
                </p>
              </div>
              <div className="flex gap-2">
                <button
                  onClick={() => setShowLogoutConfirm(false)}
                  className="flex-1 py-2.5 rounded-xl text-sm font-medium text-gray-600 bg-gray-100 hover:bg-gray-200 transition-all active:scale-95"
                >
                  Batal
                </button>
                <button
                  onClick={handleLogout}
                  className="flex-1 py-2.5 rounded-xl text-sm font-medium text-white bg-red-500 hover:bg-red-600 transition-all active:scale-95 shadow-sm shadow-red-200"
                >
                  Keluar
                </button>
              </div>
            </div>
          </div>
        </>
      )}
      <style>{`
  @keyframes slideUp {
    from { opacity: 0; transform: translateY(24px) scale(0.97); }
    to   { opacity: 1; transform: translateY(0) scale(1); }
  }
  @keyframes modalSlideUp {
    from { opacity: 0; transform: translateY(16px) scale(0.96); }
    to   { opacity: 1; transform: translateY(0) scale(1); }
  }
    @keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(6px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
`}</style>
    </>
  );
}